import (
    "io"
    "net/http"
    "os"
    "path/filepath"
    "mime/multipart"
)

func main() {
    http.HandleFunc("/upload", uploadHandler)

    http.ListenAndServe(":8080", nil)
}

func uploadHandler(w http.ResponseWriter, r *http.Request) {
    if r.Method != "POST" {
        w.WriteHeader(405) // Method Not Allowed
        return
    }

    fileHeader, err := r.FormFile("file")
    if err != nil {
        w.WriteHeader(422) // Unprocessable Entity
        io.WriteString(w, `{"error": "failed to parse file"}`)
        return
    }

    defer fileHeader.Close()

    filename := filepath.Base(fileHeader.Filename)
    contentType := fileHeader.Header["Content-Type"][0]

    if !isAllowedFile(contentType) {
        w.WriteHeader(422) // Unprocessable Entity
        io.WriteString(w, `{"error": "unsupported file type"}`)
        return
    }

    path := filepath.Join("public", filename)

    file, err := os.Create(path)
    if err != nil {
        w.WriteHeader(500) // Internal Server Error
        io.WriteString(w, `{"error": "failed to create file"}`)
        return
    }

    defer file.Close()

    _, err = io.Copy(file, fileHeader)
    if err != nil {
        w.WriteHeader(500) // Internal Server Error
        io.WriteString(w, `{"error": "failed to copy file contents"}`)
        return
    }

    io.WriteString(w, `{"path": "`+filename+`"}`)
}

func isAllowedFile(contentType string) bool {
    switch contentType {
    case "image/jpeg", "image/png", "application/pdf", "application/zip":
        return true
    default:
        return false
    }
}